  1→'use client';
  2→
  3→import { useEffect, useRef } from 'react';
  4→import type { VoiceState } from '@/hooks/useVoiceEngine';
  5→import s from './VoiceOrb.module.css';
  6→
  7→interface VoiceOrbProps {
  8→  voiceState: VoiceState;
  9→  micLevel?: number;   // 0-1
 10→  ttsLevel?: number;   // 0-1
 11→  size?: number;
 12→}
 13→
 14→export default function VoiceOrb({
 15→  voiceState,
 16→  micLevel = 0,
 17→  ttsLevel = 0,
 18→  size = 220,
 19→}: VoiceOrbProps) {
 20→  const canvasRef = useRef<HTMLCanvasElement>(null);
 21→  const frameRef = useRef<number>(0);
 22→  const phaseRef = useRef(0);
 23→
 24→  // Live values updated via refs so the rAF loop doesn't restart
 25→  const stateRef = useRef(voiceState);
 26→  const levelRef = useRef(0);
 27→
 28→  useEffect(() => {
 29→    stateRef.current = voiceState;
 30→    levelRef.current = voiceState === 'speaking' ? ttsLevel : micLevel;
 31→  }, [voiceState, micLevel, ttsLevel]);
 32→
 33→  useEffect(() => {
 34→    const canvas = canvasRef.current;
 35→    if (!canvas) return;
 36→    const ctx = canvas.getContext('2d');
 37→    if (!ctx) return;
 38→
 39→    const W = size * 2; // retina
 40→    canvas.width = W;
 41→    canvas.height = W;
 42→    const C = W / 2;
 43→    const R = C * 0.32;
 44→
 45→    const draw = () => {
 46→      phaseRef.current += 0.018;
 47→      const ph = phaseRef.current;
 48→      const lv = levelRef.current;
 49→      const vs = stateRef.current;
 50→      const thinking = vs === 'thinking';
 51→      const isActive = vs !== 'dormant';
 52→
 53→      ctx.clearRect(0, 0, W, W);
 54→
 55→      // Outer ambient glow
 56→      const ambientR = C * 0.85 + lv * C * 0.12;
 57→      const ambient = ctx.createRadialGradient(C, C, R * 0.5, C, C, ambientR);
 58→
 59→      if (thinking) {
 60→        ambient.addColorStop(0, 'rgba(228,184,74,0.12)');
 61→        ambient.addColorStop(0.5, 'rgba(228,184,74,0.04)');
 62→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 63→      } else if (vs === 'listening' || vs === 'followup') {
 64→        ambient.addColorStop(0, 'rgba(99,102,241,0.18)');
 65→        ambient.addColorStop(0.5, 'rgba(139,92,246,0.06)');
 66→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 67→      } else if (vs === 'speaking') {
 68→        ambient.addColorStop(0, 'rgba(196,181,253,0.20)');
 69→        ambient.addColorStop(0.5, 'rgba(139,92,246,0.07)');
 70→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 71→      } else {
 72→        ambient.addColorStop(0, 'rgba(99,102,241,0.06)');
 73→        ambient.addColorStop(1, 'rgba(0,0,0,0)');
 74→      }
 75→      ctx.fillStyle = ambient;
 76→      ctx.fillRect(0, 0, W, W);
 77→
 78→      // Pulse rings
 79→      for (let i = 0; i < 3; i++) {
 80→        const offset = (i / 3) * Math.PI * 2;
 81→        const pulse = Math.sin(ph * 0.8 + offset) * 0.5 + 0.5;
 82→        const ringR = R * (1.5 + i * 0.55) + lv * R * 0.6 * (1 - i * 0.2);
 83→        const alpha = isActive
 84→          ? (thinking ? 0.55 : 0.35 + pulse * 0.25) * (1 - i * 0.2)
 85→          : 0.08 + pulse * 0.04;
 86→
 87→        let color: string;
 88→        if (thinking) color = `rgba(228,184,74,${alpha})`;
 89→        else if (vs === 'speaking') color = `rgba(196,181,253,${alpha})`;
 90→        else if (vs === 'followup') color = `rgba(99,210,190,${alpha})`;
 91→        else color = `rgba(139,92,246,${alpha})`;
 92→
 93→        ctx.beginPath();
 94→        ctx.arc(C, C, ringR, 0, Math.PI * 2);
 95→        ctx.strokeStyle = color;
 96→        ctx.lineWidth = thinking ? 1.5 : 1.0 + lv * 1.5;
 97→        ctx.stroke();
 98→      }
 99→
100→      // Waveform ring
101→      if (isActive && lv > 0.02) {
102→        const waveR = R * 1.35 + lv * R * 0.4;
103→        const points = 128;
104→        ctx.beginPath();
105→        for (let p = 0; p < points; p++) {
106→        const angle = (p / points) * Math.PI * 2 - Math.PI / 2;
107→        const wave = Math.sin(angle * 8 + ph * 3) * lv * R * 0.18
108→                   + Math.sin(angle * 5 - ph * 2) * lv * R * 0.10;
109→        const r = waveR + wave;
110→        const x = C + Math.cos(angle) * r;
111→        const y = C + Math.sin(angle) * r;
112→        if (p === 0) ctx.moveTo(x, y);
113→        else ctx.lineTo(x, y);
114→      }
115→        ctx.closePath();
116→        const waveAlpha = 0.4 + lv * 0.4;
117→        ctx.strokeStyle = thinking
118→          ? `rgba(228,184,74,${waveAlpha})`
119→          : vs === 'speaking'
120→          ? `rgba(196,181,253,${waveAlpha})`
121→          : `rgba(99,102,241,${waveAlpha})`;
122→        ctx.lineWidth = 1.5;
123→        ctx.stroke();
124→      }
125→
126→      // Rotating arc (thinking)
127→      if (thinking) {
128→        ctx.save();
129→        ctx.translate(C, C);
130→        ctx.rotate(ph * 2.5);
131→        ctx.beginPath();
132→        ctx.arc(0, 0, R * 2.0, 0, Math.PI * 1.2);
133→        ctx.strokeStyle = 'rgba(228,184,74,0.7)';
134→        ctx.lineWidth = 2;
135→        ctx.lineCap = 'round';
136→        ctx.stroke();
137→        ctx.rotate(Math.PI);
138→        ctx.beginPath();
139→        ctx.arc(0, 0, R * 2.0, 0, Math.PI * 0.5);
140→        ctx.strokeStyle = 'rgba(228,184,74,0.35)';
141→        ctx.lineWidth = 1.5;
142→        ctx.stroke();
143→        ctx.restore();
144→      }
145→
146→      // Core glow
147→      const coreGlow = ctx.createRadialGradient(C, C, 0, C, C, R * 1.3);
148→      const breathe = Math.sin(ph * 0.7) * 0.5 + 0.5;
149→
150→      if (thinking) {
151→        coreGlow.addColorStop(0, `rgba(255,230,130,${0.25 + breathe * 0.15})`);
152→        coreGlow.addColorStop(0.4, `rgba(228,184,74,${0.15 + breathe * 0.10})`);
153→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
154→      } else if (vs === 'speaking') {
155→        coreGlow.addColorStop(0, `rgba(220,200,255,${0.22 + lv * 0.2})`);
156→        coreGlow.addColorStop(0.4, `rgba(139,92,246,${0.14 + lv * 0.1})`);
157→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
158→      } else if (vs === 'listening') {
159→        coreGlow.addColorStop(0, `rgba(140,120,255,${0.20 + lv * 0.25})`);
160→        coreGlow.addColorStop(0.4, `rgba(99,102,241,${0.10 + lv * 0.15})`);
161→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
162→      } else if (vs === 'followup') {
163→        coreGlow.addColorStop(0, `rgba(99,210,190,${0.18 + breathe * 0.08})`);
164→        coreGlow.addColorStop(0.4, `rgba(16,185,129,${0.10})`);
165→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
166→      } else {
167→        coreGlow.addColorStop(0, `rgba(99,102,241,${0.10 + breathe * 0.05})`);
168→        coreGlow.addColorStop(1, 'rgba(0,0,0,0)');
169→      }
170→      ctx.fillStyle = coreGlow;
171→      ctx.beginPath();
172→      ctx.arc(C, C, R * 1.3, 0, Math.PI * 2);
173→      ctx.fill();
174→
175→      frameRef.current = requestAnimationFrame(draw);
176→    };
177→
178→    draw();
179→    return () => cancelAnimationFrame(frameRef.current);
180→  }, [size]); // Only restart loop when canvas size changes
181→
182→  const stateClass = voiceState === 'thinking' ? s.thinking
183→    : voiceState === 'listening' ? s.listening
184→    : voiceState === 'speaking' ? s.speaking
185→    : voiceState === 'followup' ? s.followup
186→    : s.dormant;
187→
188→  return (
189→    <div className={`${s.orbWrap} ${stateClass}`} style={{ width: size, height: size }}>
190→      <canvas ref={canvasRef} className={s.canvas} style={{ width: size, height: size }} />
191→      <div className={s.symbol}>Ω</div>
192→    </div>
193→  );
194→}
