  1→'use client';
  2→
  3→import { useCallback, useEffect, useRef, useState } from 'react';
  4→import {
  5→  getSpeechRecognitionConstructor,
  6→  type SpeechRecognitionInstance,
  7→  type SpeechRecognitionEventLike,
  8→  type SpeechRecognitionErrorEventLike,
  9→} from '@/lib/speechRecognition';
 10→
 11→export type VoiceState = 'dormant' | 'listening' | 'thinking' | 'speaking' | 'followup';
 12→
 13→export interface VoiceEngineOptions {
 14→  onTranscript: (text: string) => void;
 15→  onTTSStart?: () => void;
 16→  onTTSEnd?: () => void;
 17→  followUpWindowMs?: number;
 18→  ttsUrl?: string;
 19→  autoStart?: boolean;
 20→  useWhisper?: boolean;
 21→}
 22→
 23→export interface VoiceEngineReturn {
 24→  voiceState: VoiceState;
 25→  interim: string;
 26→  micLevel: number;
 27→  ttsLevel: number;
 28→  supported: boolean;
 29→  toggle: () => void;
 30→  speakText: (text: string) => Promise<void>;
 31→  stopSpeaking: () => void;
 32→  wakeUp: () => void;
 33→}
 34→
 35→const WAKE_WORDS = ['mega', 'omega'];
 36→const FOLLOW_UP_MS = 25_000;
 37→const MIN_SPEECH_CHARS = 3;
 38→const SILENCE_COMMIT_MS = 1400;
 39→
 40→// Shared helper: drive an audio level meter from an AnalyserNode
 41→function startLevelTick(
 42→  analyser: AnalyserNode,
 43→  setLevel: (v: number) => void,
 44→  animRef: React.MutableRefObject<number | null>,
 45→) {
 46→  const buf = new Uint8Array(analyser.frequencyBinCount);
 47→  const tick = () => {
 48→    analyser.getByteFrequencyData(buf);
 49→    const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
 50→    setLevel(Math.min(avg / 80, 1));
 51→    animRef.current = requestAnimationFrame(tick);
 52→  };
 53→  tick();
 54→}
 55→
 56→export function useVoiceEngine({
 57→  onTranscript,
 58→  onTTSStart,
 59→  onTTSEnd,
 60→  followUpWindowMs = FOLLOW_UP_MS,
 61→  ttsUrl = '/api/tts',
 62→  autoStart = true,
 63→  useWhisper = false,
 64→}: VoiceEngineOptions): VoiceEngineReturn {
 65→  const [voiceState, setVoiceState] = useState<VoiceState>('dormant');
 66→  const [interim, setInterim] = useState('');
 67→  const [micLevel, setMicLevel] = useState(0);
 68→  const [ttsLevel, setTtsLevel] = useState(0);
 69→  const [supported, setSupported] = useState(false);
 70→
 71→  const stateRef = useRef<VoiceState>('dormant');
 72→  const recogRef = useRef<SpeechRecognitionInstance | null>(null);
 73→  const followUpTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
 74→  const audioCtxRef = useRef<AudioContext | null>(null);
 75→  const micStreamRef = useRef<MediaStream | null>(null);
 76→  const analyserRef = useRef<AnalyserNode | null>(null);
 77→  const micAnimRef = useRef<number | null>(null);
 78→  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
 79→  const ttsCtxRef = useRef<AudioContext | null>(null);
 80→  const ttsAnimRef = useRef<number | null>(null);
 81→  const mutedRef = useRef(false);
 82→  const restartTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 83→
 84→  // Whisper recording refs (only used when useWhisper=true)
 85→  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
 86→  const audioChunksRef = useRef<Blob[]>([]);
 87→  const silenceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 88→
 89→  // Stale-closure avoidance: callbacks read stateRef instead of voiceState
 90→  const setState = useCallback((s: VoiceState) => {
 91→    stateRef.current = s;
 92→    setVoiceState(s);
 93→  }, []);
 94→
 95→  // ── Shared AudioContext ────────────────────────────────────────────────────
 96→  const getAudioCtx = useCallback(() => {
 97→    if (!audioCtxRef.current || audioCtxRef.current.state === 'closed') {
 98→      audioCtxRef.current = new AudioContext();
 99→    }
100→    return audioCtxRef.current;
101→  }, []);
102→
103→  // ── Mic level analyzer ─────────────────────────────────────────────────────
104→  const startMicAnalyzer = useCallback(async () => {
105→    try {
106→      const ctx = getAudioCtx();
107→      if (!micStreamRef.current) {
108→        micStreamRef.current = await navigator.mediaDevices.getUserMedia({ audio: true, video: false });
109→      }
110→      analyserRef.current?.disconnect();
111→      const src = ctx.createMediaStreamSource(micStreamRef.current);
112→      analyserRef.current = ctx.createAnalyser();
113→      analyserRef.current.fftSize = 128;
114→      src.connect(analyserRef.current);
115→      startLevelTick(analyserRef.current, setMicLevel, micAnimRef);
116→    } catch { /* mic denied */ }
117→  }, [getAudioCtx]);
118→
119→  const stopMicAnalyzer = useCallback(() => {
120→    if (micAnimRef.current) {
121→      cancelAnimationFrame(micAnimRef.current);
122→      micAnimRef.current = null;
123→      setMicLevel(0);
124→    }
125→  }, []);
126→
127→  // ── Follow-up window ──────────────────────────────────────────────────────
128→  const clearFollowUp = useCallback(() => {
129→    if (followUpTimer.current) clearTimeout(followUpTimer.current);
130→  }, []);
131→
132→  const enterFollowUp = useCallback(() => {
133→    setState('followup');
134→    clearFollowUp();
135→    followUpTimer.current = setTimeout(() => {
136→      if (stateRef.current === 'followup') setState('dormant');
137→    }, followUpWindowMs);
138→  }, [setState, clearFollowUp, followUpWindowMs]);
139→
140→  // ── TTS playback ──────────────────────────────────────────────────────────
141→  const stopSpeaking = useCallback(() => {
142→    ttsSourceRef.current?.stop();
143→    ttsSourceRef.current = null;
144→    if (ttsAnimRef.current) {
145→      cancelAnimationFrame(ttsAnimRef.current);
146→      ttsAnimRef.current = null;
147→    }
148→    // Close the dedicated TTS AudioContext to prevent leaks
149→    if (ttsCtxRef.current) {
150→      ttsCtxRef.current.close().catch(() => {});
151→      ttsCtxRef.current = null;
152→    }
153→    setTtsLevel(0);
154→  }, []);
155→
156→  const speakText = useCallback(async (text: string): Promise<void> => {
157→    if (!text?.trim()) { enterFollowUp(); return; }
158→    stopSpeaking();
159→    setState('speaking');
160→    onTTSStart?.();
161→
162→    try {
163→      const res = await fetch(ttsUrl, {
164→        method: 'POST',
165→        headers: { 'Content-Type': 'application/json' },
166→        body: JSON.stringify({ text: text.slice(0, 2000) }),
167→      });
168→      const data = await res.json();
169→
170→      if (!data.audio) throw new Error('No audio returned');
171→
172→      const raw = atob(data.audio);
173→      const bytes = new Uint8Array(raw.length);
174→      for (let i = 0; i < raw.length; i++) bytes[i] = raw.charCodeAt(i);
175→
176→      // Dedicated context for TTS — tracked in ttsCtxRef for cleanup
177→      const ctx = new AudioContext();
178→      ttsCtxRef.current = ctx;
179→      const buffer = await ctx.decodeAudioData(bytes.buffer);
180→
181→      const analyser = ctx.createAnalyser();
182→      analyser.fftSize = 128;
183→
184→      const src = ctx.createBufferSource();
185→      src.buffer = buffer;
186→      src.connect(analyser);
187→      analyser.connect(ctx.destination);
188→      ttsSourceRef.current = src;
189→
190→      startLevelTick(analyser, setTtsLevel, ttsAnimRef);
191→
192→      src.start();
193→      src.onended = () => {
194→        if (ttsAnimRef.current) cancelAnimationFrame(ttsAnimRef.current);
195→        ttsAnimRef.current = null;
196→        setTtsLevel(0);
197→        ctx.close().catch(() => {});
198→        ttsCtxRef.current = null;
199→        onTTSEnd?.();
200→        enterFollowUp();
201→      };
202→    } catch (e) {
203→      console.warn('[VoiceEngine] TTS error:', e);
204→      onTTSEnd?.();
205→      enterFollowUp();
206→    }
207→  }, [ttsUrl, stopSpeaking, setState, enterFollowUp, onTTSStart, onTTSEnd]);
208→
209→  // ── Speech recognition ────────────────────────────────────────────────────
210→  const stopRecognition = useCallback(() => {
211→    try { recogRef.current?.stop(); } catch { /* ignore */ }
212→  }, []);
213→
214→  const startRecognition = useCallback(() => {
215→    const SR = getSpeechRecognitionConstructor();
216→    if (!SR) return;
217→
218→    stopRecognition();
219→
220→    const r = new SR();
221→    r.continuous = true;
222→    r.interimResults = true;
223→    r.lang = 'en-US';
224→    r.maxAlternatives = 1;
225→    recogRef.current = r;
226→
227→    let finalBuffer = '';
228→    let silenceTimer: ReturnType<typeof setTimeout> | null = null;
229→
230→    const resetSilence = () => {
231→      if (silenceTimer) clearTimeout(silenceTimer);
232→      silenceTimer = setTimeout(() => {
233→        if (finalBuffer.trim().length >= MIN_SPEECH_CHARS &&
234→            (stateRef.current === 'listening' || stateRef.current === 'followup')) {
235→          const text = finalBuffer.trim();
236→          finalBuffer = '';
237→          setInterim('');
238→          stopMicAnalyzer();
239→          setState('thinking');
240→          onTranscript(text);
241→        }
242→      }, SILENCE_COMMIT_MS);
243→    };
244→
245→    r.onresult = (e: SpeechRecognitionEventLike) => {
246→      let interimText = '';
247→      let newFinal = '';
248→
249→      for (let i = e.resultIndex; i < e.results.length; i++) {
250→        const t = e.results[i][0].transcript;
251→        if (e.results[i].isFinal) newFinal += t + ' ';
252→        else interimText += t;
253→      }
254→
255→      if (newFinal) {
256→        finalBuffer += newFinal;
257→        resetSilence();
258→      }
259→
260→      setInterim((finalBuffer + interimText).trim());
261→
262→      if (stateRef.current === 'dormant') {
263→        const all = (finalBuffer + interimText).toLowerCase();
264→        if (WAKE_WORDS.some(w => all.includes(w))) {
265→          finalBuffer = '';
266→          setInterim('');
267→          setState('listening');
268→          startMicAnalyzer();
269→        }
270→      }
271→    };
272→
273→    r.onspeechstart = () => {
274→      if (stateRef.current === 'dormant') return;
275→      if (stateRef.current === 'followup') {
276→        clearFollowUp();
277→        setState('listening');
278→        startMicAnalyzer();
279→      }
280→    };
281→
282→    r.onerror = (e: SpeechRecognitionErrorEventLike) => {
283→      if (e.error === 'no-speech' || e.error === 'aborted') return;
284→      console.warn('[VoiceEngine] Recognition error:', e.error);
285→    };
286→
287→    r.onend = () => {
288→      if (!mutedRef.current &&
289→          stateRef.current !== 'thinking' &&
290→          stateRef.current !== 'speaking') {
291→        restartTimerRef.current = setTimeout(() => {
292→          restartTimerRef.current = null;
293→          if (!mutedRef.current) startRecognition();
294→        }, 200);
295→      }
296→    };
297→
298→    try { r.start(); } catch { /* already running */ }
299→  }, [stopRecognition, stopMicAnalyzer, setState, startMicAnalyzer, onTranscript, clearFollowUp]);
300→
301→  // ── Whisper recording ─────────────────────────────────────────────────────
302→  const startWhisperRecording = useCallback(async () => {
303→    try {
304→      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
305→      micStreamRef.current = stream;
306→      const recorder = new MediaRecorder(stream, { mimeType: 'audio/webm' });
307→      audioChunksRef.current = [];
308→      mediaRecorderRef.current = recorder;
309→
310→      recorder.ondataavailable = (e) => {
311→        if (e.data.size > 0) audioChunksRef.current.push(e.data);
312→      };
313→
314→      recorder.onstop = async () => {
315→        const blob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
316→        audioChunksRef.current = [];
317→        if (blob.size < 1000) { setState('listening'); startWhisperRecording(); return; }
318→
319→        setState('thinking');
320→        const form = new FormData();
321→        form.append('audio', blob, 'recording.webm');
322→        try {
323→          const res = await fetch('/api/stt', { method: 'POST', body: form });
324→          const data = await res.json();
325→          if (data.text?.trim()) {
326→            onTranscript(data.text.trim());
327→          } else {
328→            setState('listening');
329→            startWhisperRecording();
330→          }
331→        } catch {
332→          setState('listening');
333→          startWhisperRecording();
334→        }
335→      };
336→
337→      recorder.start(100); // collect chunks every 100ms
338→
339→      // Silence detection via analyser
340→      const ctx = getAudioCtx();
341→      const src = ctx.createMediaStreamSource(stream);
342→      const analyser = ctx.createAnalyser();
343→      analyser.fftSize = 128;
344→      src.connect(analyser);
345→      analyserRef.current = analyser;
346→      startLevelTick(analyser, setMicLevel, micAnimRef);
347→
348→      const buf = new Uint8Array(analyser.frequencyBinCount);
349→      const checkSilence = () => {
350→        analyser.getByteFrequencyData(buf);
351→        const avg = buf.reduce((a, b) => a + b, 0) / buf.length;
352→        if (avg < 5) {
353→          if (!silenceTimerRef.current) {
354→            silenceTimerRef.current = setTimeout(() => {
355→              silenceTimerRef.current = null;
356→              if (mediaRecorderRef.current?.state === 'recording') {
357→                stopMicAnalyzer();
358→                mediaRecorderRef.current.stop();
359→              }
360→            }, 1500);
361→          }
362→        } else {
363→          if (silenceTimerRef.current) {
364→            clearTimeout(silenceTimerRef.current);
365→            silenceTimerRef.current = null;
366→          }
367→        }
368→        if (stateRef.current === 'listening') requestAnimationFrame(checkSilence);
369→      };
370→      requestAnimationFrame(checkSilence);
371→    } catch (e) {
372→      console.warn('[VoiceEngine] Whisper recording failed:', e);
373→    }
374→  }, [getAudioCtx, onTranscript, setState, stopMicAnalyzer]);
375→
376→  // ── Public controls ───────────────────────────────────────────────────────
377→  const wakeUp = useCallback(() => {
378→    clearFollowUp();
379→    setState('listening');
380→    startMicAnalyzer();
381→  }, [setState, clearFollowUp, startMicAnalyzer]);
382→
383→  const toggle = useCallback(() => {
384→    if (stateRef.current === 'dormant') {
385→      mutedRef.current = false;
386→      if (useWhisper) {
387→        setState('listening');
388→        startWhisperRecording();
389→      } else {
390→        wakeUp();
391→        startRecognition();
392→      }
393→    } else {
394→      mutedRef.current = true;
395→      if (useWhisper) {
396→        if (silenceTimerRef.current) {
397→          clearTimeout(silenceTimerRef.current);
398→          silenceTimerRef.current = null;
399→        }
400→        if (mediaRecorderRef.current?.state === 'recording') {
401→          mediaRecorderRef.current.stop();
402→        }
403→        mediaRecorderRef.current = null;
404→      } else {
405→        stopRecognition();
406→      }
407→      stopSpeaking();
408→      stopMicAnalyzer();
409→      clearFollowUp();
410→      setState('dormant');
411→    }
412→  }, [useWhisper, wakeUp, startRecognition, startWhisperRecording, stopRecognition, stopSpeaking, stopMicAnalyzer, clearFollowUp, setState]);
413→
414→  // ── Init ──────────────────────────────────────────────────────────────────
415→  useEffect(() => {
416→    const hasSR = typeof window !== 'undefined' &&
417→      !!getSpeechRecognitionConstructor();
418→    setSupported(useWhisper ? true : hasSR);
419→    if (!autoStart) return;
420→
421→    if (useWhisper) {
422→      const t = setTimeout(() => {
423→        mutedRef.current = false;
424→        setState('listening');
425→        startWhisperRecording();
426→      }, 800);
427→      return () => {
428→        clearTimeout(t);
429→        if (silenceTimerRef.current) clearTimeout(silenceTimerRef.current);
430→        if (mediaRecorderRef.current?.state === 'recording') mediaRecorderRef.current.stop();
431→        mutedRef.current = true;
432→        stopMicAnalyzer();
433→        clearFollowUp();
434→      };
435→    }
436→
437→    if (!hasSR) return;
438→
439→    const t = setTimeout(() => {
440→      mutedRef.current = false;
441→      startRecognition();
442→      setState('listening');
443→      startMicAnalyzer();
444→    }, 800);
445→
446→    return () => {
447→      clearTimeout(t);
448→      if (restartTimerRef.current) clearTimeout(restartTimerRef.current);
449→      mutedRef.current = true;
450→      stopRecognition();
451→      stopMicAnalyzer();
452→      clearFollowUp();
453→    };
454→    // eslint-disable-next-line react-hooks/exhaustive-deps
455→  }, []);
456→
457→  // Restart recognition whenever we enter listening or followup.
458→  // recogRef is never nulled after first start, so we can't use it as a
459→  // "is running" guard — always restart to ensure the mic is live.
460→  useEffect(() => {
461→    if (!useWhisper && (voiceState === 'listening' || voiceState === 'followup')) {
462→      startRecognition();
463→    }
464→  }, [useWhisper, voiceState, startRecognition]);
465→
466→  return { voiceState, interim, micLevel, ttsLevel, supported, toggle, speakText, stopSpeaking, wakeUp };
467→}
