 5→ * Accepts: multipart/form-data with field "audio" (webm/wav/mp3/m4a)
 6→ * Returns: { text: string }
 7→ * Uses OpenAI Whisper API
 8→ */
 9→export async function POST(req: NextRequest) {
10→  try {
11→    const key = process.env.OPENAI_API_KEY;
12→    if (!key) {
13→      return NextResponse.json({ error: 'STT unavailable — no API key' }, { status: 503 });
14→    }
15→
16→    const formData = await req.formData();
17→    const audioFile = formData.get('audio') as File | null;
18→
19→    if (!audioFile) {
20→      return NextResponse.json({ error: 'No audio file provided' }, { status: 400 });
21→    }
22→
23→    // Forward to OpenAI Whisper
24→    const whisperForm = new FormData();
25→    whisperForm.append('file', audioFile, audioFile.name || 'audio.wav');
26→    whisperForm.append('model', 'whisper-1');
27→    whisperForm.append('language', 'en');
28→
29→    const res = await fetch('https://api.openai.com/v1/audio/transcriptions', {
30→      method: 'POST',
31→      headers: { Authorization: `Bearer ${key}` },
32→      body: whisperForm,
33→    });
34→
35→    if (!res.ok) {
36→      const err = await res.text();
37→      console.error('[OmegA STT] Whisper error:', err);
38→      return NextResponse.json({ error: 'Transcription failed' }, { status: 502 });
