127→    const relevant = await db`
128→      SELECT LEFT(content, 2000) AS content, created_at
129→      FROM omega_memory_entries
130→      WHERE content ILIKE ${pattern}
131→      ORDER BY created_at DESC
132→      LIMIT 10
133→    `.catch(() => [] as Row[]);
134→
135→    if ((relevant as Row[]).length > 0) {
136→      sections.push('\n=== QUERY-RELEVANT ENTRIES ===');
