142→  if ((marginalia as Row[]).length > 0) {
143→    sections.push('\n=== MARGINALIA ===');
144→    for (const m of marginalia as Row[]) sections.push(JSON.stringify(m));
145→  }
146→
147→  const events = await db`SELECT * FROM omega_events ORDER BY created_at DESC LIMIT 15`.catch(() => [] as Row[]);
148→  if ((events as Row[]).length > 0) {
