324→export async function POST(req: NextRequest) {
325→  try {
326→    const { user, history, sessionId, voiceMode } = (await req.json()) as { user: string; history?: Msg[]; sessionId?: string; voiceMode?: boolean };
327→
328→    if (!user?.trim()) {
