342→      }
343→    }
344→
345→    const encoder = new TextEncoder();
346→    const decoder = new TextDecoder();
347→
348→    if (dbUrl && finalSessionId) {
349→      const db = neon(dbUrl);
350→      try {
351→        await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'user', ${user})`;
352→      } catch (e) {
353→        console.error('[OmegA] DB write error', e);
354→      }
355→    }
356→
357→    let rawContext: string;
358→    try {
359→      rawContext = await pullRawContext(user);
360→    } catch (e) {
361→      console.warn('[OmegA] DB pull failed:', e);
362→      rawContext = '(Memory bank unreachable — reasoning independently)';
363→    }
364→
365→    const conversationContext = history?.length
366→      ? `\n━━━ SESSION CONVERSATION HISTORY ━━━\n\n` +
367→        history.map(m => `[${m.role === 'omega' ? 'OmegA' : 'User'}]: ${m.text}`).join('\n\n') +
368→        `\n\n━━━ END HISTORY ━━━\n`
369→      : '';
370→
371→    const voiceDirective = voiceMode ? `\n\n━━━ VOICE MODE ━━━\nYou are speaking aloud. The user will hear your response via text-to-speech.\nRules:\n- Keep responses under 3 sentences unless a longer answer is truly necessary.\n- No markdown formatting, no bullet points, no headers — plain spoken sentences only.\n- No "certainly", "of course", "absolutely". Just answer directly.\n- If you need to think through something complex, say one sentence summary then offer to go deeper.\n━━━ END VOICE MODE ━━━` : '';
372→    const system = `${SYNTHESIS_DIRECTIVE}\n\n${ANTI_ECHO_DIRECTIVE}\n\n━━━ RAW DATA FROM MEMORY SYSTEMS ━━━\n\n${rawContext}\n\n━━━ END RAW DATA ━━━\n${conversationContext}${voiceDirective}`;
373→
374→    const providerHealth = getProviderHealthSnapshot();
375→    const providerFns: Record<ProviderName, () => Promise<ReadableStream>> = {
376→      'vercel-gateway': () => tryVercelGateway(encoder, system, user, history),
