382→    const providers = getProviderOrder().map(name => ({ name, fn: providerFns[name] }));
383→    const selection = await selectStreamingProvider(providers, encoder, decoder);
384→    const { provider, stream: providerStream, attempts: providerAttempts } = selection;
385→
386→    const customStream = new ReadableStream({
387→      async start(controller) {
388→        try {
389→          controller.enqueue(encoder.encode('data: {"type":"status","text":"reading memory..."}\n\n'));
390→          controller.enqueue(encoder.encode('data: {"type":"status","text":"synthesizing..."}\n\n'));
391→
392→          const reader = providerStream.getReader();
393→          let fullResponse = '';
394→          while (true) {
395→            const { value, done } = await reader.read();
396→            if (done) break;
397→            const text = decoder.decode(value, { stream: true });
398→            if (text) {
399→              fullResponse += text;
400→              controller.enqueue(encoder.encode(text));
401→            }
402→          }
403→
404→          if (dbUrl && finalSessionId && fullResponse) {
405→            const db = neon(dbUrl);
406→            try {
407→              await db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${fullResponse})`;
