410→            }
411→          }
412→
413→          controller.close();
414→        } catch (err) {
415→          console.error('[OmegA] Stream error', err);
416→          controller.error(err);
417→        }
418→      }
419→    });
420→
421→    return new NextResponse(customStream, {
422→      headers: {
