108→export async function selectStreamingProvider(
109→  providers: Array<{ name: ProviderName; fn: () => Promise<ReadableStream> }>,
110→  encoder: TextEncoder,
111→  decoder: TextDecoder,
112→): Promise<{
113→  provider: ProviderName;
114→  stream: ReadableStream;
115→  attempts: ProviderAttempt[];
116→}> {
117→  let lastErr: unknown;
118→  const attempts: ProviderAttempt[] = [];
119→
120→  for (const p of providers) {
121→    try {
122→      const providerStream = await p.fn();
123→      const selected = await promoteNonEmptyStream(providerStream, encoder, decoder);
124→      if (selected) {
125→        attempts.push({ name: p.name, status: 'selected' });
126→        return { provider: p.name, stream: selected, attempts };
127→      }
128→      attempts.push({ name: p.name, status: 'failed', error: 'empty response' });
129→    } catch (e) {
130→      const error = e instanceof Error ? e.message : String(e);
131→      attempts.push({ name: p.name, status: 'failed', error });
132→      lastErr = e;
133→    }
134→  }
135→
136→  throw lastErr ?? new Error(`All providers failed (${attempts.map(p => p.name).join(' -> ')})`);
137→}
138→
139→async function promoteNonEmptyStream(
140→  providerStream: ReadableStream,
141→  encoder: TextEncoder,
142→  decoder: TextDecoder,
143→): Promise<ReadableStream | null> {
144→  const reader = providerStream.getReader();
145→  const bufferedChunks: string[] = [];
146→  let sawMeaningfulChunk = false;
147→
148→  try {
149→    while (true) {
150→      const { value, done } = await reader.read();
151→      if (done) break;
152→      const text = decoder.decode(value, { stream: true });
153→      if (text) {
154→        bufferedChunks.push(text);
155→        if (text.trim()) {
156→          sawMeaningfulChunk = true;
157→          break;
158→        }
159→      }
160→    }
161→
162→    if (!sawMeaningfulChunk) {
163→      await reader.cancel().catch(() => {});
164→      return null;
165→    }
166→
167→    return new ReadableStream({
168→      async start(ctrl) {
169→        try {
170→          for (const chunk of bufferedChunks) {
171→            ctrl.enqueue(encoder.encode(chunk));
172→          }
173→          while (true) {
174→            const { value, done } = await reader.read();
175→            if (done) break;
176→            const text = decoder.decode(value, { stream: true });
177→            if (text) ctrl.enqueue(encoder.encode(text));
178→          }
179→          ctrl.close();
180→        } catch (err) {
181→          ctrl.error(err);
182→        }
183→      },
184→    });
185→  } catch (err) {
186→    await reader.cancel().catch(() => {});
187→    throw err;
188→  }
189→}
