114→// ── Verifier ──────────────────────────────────────────────────────────────────
115→
116→function verify(response: string, query: string): { V: number; passed: boolean; outcome: string } {
117→  const words = response.split(/\s+/);
118→  const N = Math.max(words.length, 1);
119→
120→  const certaintyWords = ['definitely', 'certainly', 'absolutely', 'always', 'never'];
121→  const hedgeWords = ['perhaps', 'maybe', 'possibly', 'might', 'could'];
122→
123→  const h = words.filter(w => certaintyWords.includes(w.toLowerCase())).length;
124→  const hedge = words.filter(w => hedgeWords.includes(w.toLowerCase())).length;
125→
126→  const qTerms = new Set(tokenize(query));
127→  const rTerms = new Set(tokenize(response));
128→  const overlap = [...qTerms].filter(t => rTerms.has(t)).length;
129→  const coverage = qTerms.size > 0 ? overlap / qTerms.size : 1;
130→
131→  const V = Math.max(0, Math.min(1, 1 - (h / N + 0.3 * (1 - coverage) + 0.3 * hedge / N)));
132→  const passed = V > 0.4;
133→  return { V, passed, outcome: passed ? 'verified' : 'uncertain' };
134→}
